INSERT INTO public.questions (id, exam_id, paper_id, subject_id, chapter_id, question_type, question_text, options, correct_answer, correct_answer_json, auto_gradable, source, is_active, version, source_meta, explanation)
VALUES
  ('elementary-e0adf6cd-moex-00009', 'elementary-e0adf6cd', 'elementary-e0adf6cd-moex-114-b3f42868', 'sub-elementary-e0adf6cd-01', NULL, 'single_choice', '不少研究發現，在異性戀伴侶中，大部分家務和照顧孩子的工作，是女方責任。根據勞動部統計，2020年 育嬰留職停薪初次核付件數，男女比例還是以女性居多，超過8成。綜上所述，從家務勞動的角度推論， 下列敘述何者為正確？', '["家務勞動的主力是女性，發生於私領域不涉及社會生活", "為肯定家務勞動價值，民法規定夫妻要協議自由處分金", "家務勞動分工與育嬰的現象與職場上男女薪資差異有關", "依勞動參與率計算公式，家務勞動者被歸類為非勞動力"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:29:36+00:00", "source_pdf_sha1": "e1455ee2159f", "answer_pdf_sha1": "c91e411dad10", "source_family": "moex-gov-tw", "moex": {"exam_code": "114010", "c": "507", "s": "0102", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "公民與英文", "year": "114", "exam_name": "114年公務人員初等考試", "original_question_number": 9, "answer_corrected": false, "flags": [], "civil_slug": "elementary", "civil_category": "教育行政"}'::jsonb, NULL),
  ('elementary-e0adf6cd-moex-00010', 'elementary-e0adf6cd', 'elementary-e0adf6cd-moex-114-b3f42868', 'sub-elementary-e0adf6cd-01', NULL, 'single_choice', '跨太平洋夥伴全面進步協定（CPTPP）是一個多邊關係的自由貿易協定，成員國人口規模將近 5 億，總 GDP占全球13.1%，貿易值占我國貿易總值超過24%。2021年9月中國提出申請加入CPTPP書面信函， 位於亞太地區的我國亦延續加入世界貿易組織的模式遞交入會申請函。根據上述，下列何者正確？', '["該組織由美國主導，為印太戰略布局與RCEP互別苗頭", "中國申請加入，意在取代美國於該組織中的領導地位", "成為該組織成員不以國家為要件，經濟體亦可申請加入", "我國與中國皆申請加入該組織，顯見中國放棄一中原則"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:29:36+00:00", "source_pdf_sha1": "e1455ee2159f", "answer_pdf_sha1": "c91e411dad10", "source_family": "moex-gov-tw", "moex": {"exam_code": "114010", "c": "507", "s": "0102", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "公民與英文", "year": "114", "exam_name": "114年公務人員初等考試", "original_question_number": 10, "answer_corrected": false, "flags": [], "civil_slug": "elementary", "civil_category": "教育行政"}'::jsonb, NULL),
  ('elementary-e0adf6cd-moex-00011', 'elementary-e0adf6cd', 'elementary-e0adf6cd-moex-114-b3f42868', 'sub-elementary-e0adf6cd-01', NULL, 'single_choice', '某公營電視台播出時，螢幕下方的跑馬燈呈現某市遭敵軍攻擊、某港爆炸，還有規模七的地震等訊息，讓 許多觀眾見到這些「獨家新聞」大驚失色，該電視台立即更正說明是「誤植」，並且向公眾道歉。在野黨 則舉行記者會強烈質疑該電視台失職，要求嚴正查辦，甚至將該電視台撤照，其董事長、總經理也必須為 此失誤下台負責。下列那一項解讀可能為此事件的最適切說明？', '["報導符合媒體在「設定議題、促進討論」的公共角色", "此為「媒體再現」的結果，與社會事實可能有所出入", "重要訊息在產製過程中，新聞守門人未善盡把關職責", "報導內容誇大不實誤導大眾，使閱聽者陷入總白癡化"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:29:36+00:00", "source_pdf_sha1": "e1455ee2159f", "answer_pdf_sha1": "c91e411dad10", "source_family": "moex-gov-tw", "moex": {"exam_code": "114010", "c": "507", "s": "0102", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "公民與英文", "year": "114", "exam_name": "114年公務人員初等考試", "original_question_number": 11, "answer_corrected": false, "flags": [], "civil_slug": "elementary", "civil_category": "教育行政"}'::jsonb, NULL),
  ('elementary-e0adf6cd-moex-00012', 'elementary-e0adf6cd', 'elementary-e0adf6cd-moex-114-b3f42868', 'sub-elementary-e0adf6cd-01', NULL, 'single_choice', '承上題，在野黨舉行記者會譴責該公營電視台失職以及懲處高層人員的作法，是希望相關人員為此負起何 項責任？', '["行政責任", "刑事責任", "民事責任", "道德責任"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:29:36+00:00", "source_pdf_sha1": "e1455ee2159f", "answer_pdf_sha1": "c91e411dad10", "source_family": "moex-gov-tw", "moex": {"exam_code": "114010", "c": "507", "s": "0102", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "公民與英文", "year": "114", "exam_name": "114年公務人員初等考試", "original_question_number": 12, "answer_corrected": false, "flags": [], "civil_slug": "elementary", "civil_category": "教育行政"}'::jsonb, NULL),
  ('elementary-e0adf6cd-moex-00013', 'elementary-e0adf6cd', 'elementary-e0adf6cd-moex-114-b3f42868', 'sub-elementary-e0adf6cd-01', NULL, 'single_choice', '我國政府在外交政策上致力於和平與發展，建立與邦交國永續夥伴關係，並與友好國家深化與廣化多元領 域的實質關係，持續爭取國際參與及對國際社會作出貢獻，發揮軟實力並透過國際合作及人道救援等方 式，提升臺灣的國際形象。由上述可知，我國致力於以何種方式參與國際事務？', '["官方交流", "踏實外交", "共同防禦", "宣示主權"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:29:36+00:00", "source_pdf_sha1": "e1455ee2159f", "answer_pdf_sha1": "c91e411dad10", "source_family": "moex-gov-tw", "moex": {"exam_code": "114010", "c": "507", "s": "0102", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "公民與英文", "year": "114", "exam_name": "114年公務人員初等考試", "original_question_number": 13, "answer_corrected": false, "flags": [], "civil_slug": "elementary", "civil_category": "教育行政"}'::jsonb, NULL),
  ('elementary-e0adf6cd-moex-00014', 'elementary-e0adf6cd', 'elementary-e0adf6cd-moex-114-b3f42868', 'sub-elementary-e0adf6cd-01', NULL, 'single_choice', '電影「老鷹想飛」記錄了臺灣田間傳統農法使用落葉劑以快速採收紅豆，卻造成很多禽鳥誤食中毒，老鷹又 吃這些中毒的禽鳥也因而死亡，本片喚醒了許多民眾對於土壤生態的意識。以上所述屬於經濟學的何種現象？', '["機會成本", "外部成本", "政府失靈", "外顯成本"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:29:36+00:00", "source_pdf_sha1": "e1455ee2159f", "answer_pdf_sha1": "c91e411dad10", "source_family": "moex-gov-tw", "moex": {"exam_code": "114010", "c": "507", "s": "0102", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "公民與英文", "year": "114", "exam_name": "114年公務人員初等考試", "original_question_number": 14, "answer_corrected": false, "flags": [], "civil_slug": "elementary", "civil_category": "教育行政"}'::jsonb, NULL),
  ('elementary-e0adf6cd-moex-00015', 'elementary-e0adf6cd', 'elementary-e0adf6cd-moex-114-b3f42868', 'sub-elementary-e0adf6cd-01', NULL, 'single_choice', '下列何者不是將制衡機制納入政府體制設計之理由？', '["避免人民的自由與權利受到侵害", "有效監督政府權力行使之合法性", "促使公共事務之推動更有效率", "避免政府權力過度集中而被濫用"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:29:36+00:00", "source_pdf_sha1": "e1455ee2159f", "answer_pdf_sha1": "c91e411dad10", "source_family": "moex-gov-tw", "moex": {"exam_code": "114010", "c": "507", "s": "0102", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "公民與英文", "year": "114", "exam_name": "114年公務人員初等考試", "original_question_number": 15, "answer_corrected": false, "flags": [], "civil_slug": "elementary", "civil_category": "教育行政"}'::jsonb, NULL),
  ('elementary-e0adf6cd-moex-00016', 'elementary-e0adf6cd', 'elementary-e0adf6cd-moex-114-b3f42868', 'sub-elementary-e0adf6cd-01', NULL, 'single_choice', '下列何者不是政府權力間制衡機制之設計？', '["司法違憲審查制度", "政府預算提案與審議分開", "立法機關行使人事同意權", "外交與國防互不隸屬"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:29:36+00:00", "source_pdf_sha1": "e1455ee2159f", "answer_pdf_sha1": "c91e411dad10", "source_family": "moex-gov-tw", "moex": {"exam_code": "114010", "c": "507", "s": "0102", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "公民與英文", "year": "114", "exam_name": "114年公務人員初等考試", "original_question_number": 16, "answer_corrected": false, "flags": [], "civil_slug": "elementary", "civil_category": "教育行政"}'::jsonb, NULL),
  ('elementary-e0adf6cd-moex-00017', 'elementary-e0adf6cd', 'elementary-e0adf6cd-moex-114-b3f42868', 'sub-elementary-e0adf6cd-01', NULL, 'single_choice', '總統制國家講求權力分立，下列何者不是此一體制下行政權與立法權互相制衡之設計？', '["覆議否決權", "人事同意權", "彈劾權", "罷免權"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:29:36+00:00", "source_pdf_sha1": "e1455ee2159f", "answer_pdf_sha1": "c91e411dad10", "source_family": "moex-gov-tw", "moex": {"exam_code": "114010", "c": "507", "s": "0102", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "公民與英文", "year": "114", "exam_name": "114年公務人員初等考試", "original_question_number": 17, "answer_corrected": false, "flags": [], "civil_slug": "elementary", "civil_category": "教育行政"}'::jsonb, NULL),
  ('elementary-e0adf6cd-moex-00018', 'elementary-e0adf6cd', 'elementary-e0adf6cd-moex-114-b3f42868', 'sub-elementary-e0adf6cd-01', NULL, 'single_choice', '根據我國地方制度法之規定，下列那一個地方層級與其他三者不同？', '["嘉義市", "基隆市", "彰化市", "花蓮縣"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:29:36+00:00", "source_pdf_sha1": "e1455ee2159f", "answer_pdf_sha1": "c91e411dad10", "source_family": "moex-gov-tw", "moex": {"exam_code": "114010", "c": "507", "s": "0102", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "公民與英文", "year": "114", "exam_name": "114年公務人員初等考試", "original_question_number": 18, "answer_corrected": false, "flags": [], "civil_slug": "elementary", "civil_category": "教育行政"}'::jsonb, NULL)
